const e=JSON.parse('{"key":"v-622baab1","path":"/MyNotes/Session%E5%92%8CCookie.html","title":"Session和Cookie","lang":"zh-CN","frontmatter":{"icon":"/icon/cookie.svg","date":"2023-10-16T00:00:00.000Z","category":["项目技术"],"footer":"霁月难逢，彩云易散。","tag":["Session","Cookie"],"description":"Session和Cookie Http无状态 HTTP无状态协议，是指协议对于交互性场景没有记忆能力。通俗理解就是你这次登录之后，你下次使用相同的用户名和密码登录，服务器并不知道还是你。 Cookie 实现每次HTTP请求都自动带数据给服务器的技术。如果没有Session。浏览器第一次发送HTTP请求，服务器会进行Cookie设置，也就是Set-Cookie，里面有名和值两个重要的属性。服务器会把名和值属性里的内容给填充完整。发给浏览器以后，浏览器会保存起来。这样浏览器以后发送的每一个请求都会自动附上这个Cookie。说白了Cookie就是一种存储在浏览器的数据而已。但是把用户名和密码保存在Cookie里面是很不安全的。只要电脑被黑，在Cookie里面的重要信息就会被泄露。于是出现了Session(会话)。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/MyNotes/Session%E5%92%8CCookie.html"}],["meta",{"property":"og:site_name","content":"TenSoFlowBlog"}],["meta",{"property":"og:title","content":"Session和Cookie"}],["meta",{"property":"og:description","content":"Session和Cookie Http无状态 HTTP无状态协议，是指协议对于交互性场景没有记忆能力。通俗理解就是你这次登录之后，你下次使用相同的用户名和密码登录，服务器并不知道还是你。 Cookie 实现每次HTTP请求都自动带数据给服务器的技术。如果没有Session。浏览器第一次发送HTTP请求，服务器会进行Cookie设置，也就是Set-Cookie，里面有名和值两个重要的属性。服务器会把名和值属性里的内容给填充完整。发给浏览器以后，浏览器会保存起来。这样浏览器以后发送的每一个请求都会自动附上这个Cookie。说白了Cookie就是一种存储在浏览器的数据而已。但是把用户名和密码保存在Cookie里面是很不安全的。只要电脑被黑，在Cookie里面的重要信息就会被泄露。于是出现了Session(会话)。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2024-06-13T15:26:01.000Z"}],["meta",{"property":"article:author","content":"TenSoFlow"}],["meta",{"property":"article:tag","content":"Session"}],["meta",{"property":"article:tag","content":"Cookie"}],["meta",{"property":"article:published_time","content":"2023-10-16T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2024-06-13T15:26:01.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Session和Cookie\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2023-10-16T00:00:00.000Z\\",\\"dateModified\\":\\"2024-06-13T15:26:01.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"TenSoFlow\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"Http无状态","slug":"http无状态","link":"#http无状态","children":[]},{"level":2,"title":"Cookie","slug":"cookie","link":"#cookie","children":[]},{"level":2,"title":"Session","slug":"session","link":"#session","children":[]},{"level":2,"title":"Token","slug":"token","link":"#token","children":[]}],"git":{"createdTime":1718292361000,"updatedTime":1718292361000,"contributors":[{"name":"tensoflower","email":"2803391693@qq.com","commits":1}]},"readingTime":{"minutes":2.34,"words":701},"filePathRelative":"MyNotes/Session和Cookie.md","localizedDate":"2023年10月16日","excerpt":"<h1> Session和Cookie</h1>\\n<h2> Http无状态</h2>\\n<p>HTTP无状态协议，是指协议对于交互性场景没有记忆能力。通俗理解就是你这次登录之后，你下次使用相同的用户名和密码登录，服务器并不知道还是你。</p>\\n<h2> Cookie</h2>\\n<p><strong>实现每次HTTP请求都自动带数据给服务器的技术</strong>。如果没有Session。浏览器第一次发送HTTP请求，服务器会进行Cookie设置，也就是Set-Cookie，里面有名和值两个重要的属性。服务器会把名和值属性里的内容给填充完整。发给浏览器以后，浏览器会保存起来。这样浏览器以后发送的每一个请求都会自动附上这个Cookie。说白了Cookie就是一种存储在浏览器的数据而已。但是把用户名和密码保存在Cookie里面是很不安全的。只要电脑被黑，在Cookie里面的重要信息就会被泄露。于是出现了Session(会话)。</p>","copyright":{"author":"TenSoFlower","license":"MIT协议"},"autoDesc":true}');export{e as data};
